     1→/**
     2→ * Entire CLI checkpoint indexer.
     3→ *
     4→ * Reads the shard-tree produced by `entire commit` on the `entire/checkpoints/v1`
     5→ * branch and writes Checkpoint / CheckpointSession / CheckpointMessage records
     6→ * into the SQLite database.
     7→ *
     8→ * Directory layout expected under the root:
     9→ *   <root>/<shard2>/<id10>/metadata.json
    10→ *   <root>/<shard2>/<id10>/0/metadata.json
    11→ *   <root>/<shard2>/<id10>/0/full.jsonl
    12→ *   <root>/<shard2>/<id10>/1/metadata.json    (if multiple sessions)
    13→ *   <root>/<shard2>/<id10>/1/full.jsonl
    14→ *   ...
    15→ */
    16→
    17→import { readdirSync, readFileSync, existsSync, statSync } from "fs";
    18→import { join } from "path";
    19→import type { PrismaClient } from "../prisma/generated/client/index.js";
    20→import { findCommitForCheckpoint } from "./gitUtils.js";
    21→
    22→// ─── Raw shapes from the checkpoint files ─────────────────────────────────────
    23→
    24→interface RootMeta {
    25→  cli_version?: string;
    26→  checkpoint_id?: string;
    27→  strategy?: string;
    28→  branch?: string;
    29→  checkpoints_count?: number;
    30→  files_touched?: string[];
    31→  token_usage?: Record<string, unknown>;
    32→}
    33→
    34→interface SummaryLearnings {
    35→  repo?: string[];
    36→  code?: Array<{ path: string; finding: string }>;
    37→  workflow?: string[];
    38→}
    39→
    40→interface SessionSummary {
    41→  intent?: string;
    42→  outcome?: string;
    43→  learnings?: SummaryLearnings;
    44→  friction?: string[];
    45→  open_items?: string[];
    46→}
    47→
    48→interface SessionMeta {
    49→  session_id: string;
    50→  checkpoint_id?: string;
    51→  cli_version?: string;
    52→  strategy?: string;
    53→  created_at?: string;
    54→  branch?: string;
    55→  checkpoints_count?: number;
    56→  turn_id?: string;
    57→  agent?: string;
    58→  token_usage?: Record<string, unknown>;
    59→  initial_attribution?: Record<string, unknown>;
    60→  files_touched?: string[];
    61→  summary?: SessionSummary;
    62→  checkpoint_transcript_start?: number;
    63→  transcript_lines_at_start?: number;
    64→}
    65→
    66→// A single line from full.jsonl — fields vary by type
    67→export interface FullJsonlEvent {
    68→  uuid?: string;
    69→  messageId?: string;      // used by "file-history-snapshot" instead of uuid
    70→  sessionId?: string;
    71→  parentUuid?: string;
    72→  type: string;
    73→  timestamp?: string;
    74→  cwd?: string;
    75→  gitBranch?: string;
    76→  slug?: string;
    77→  version?: string;
    78→  planContent?: string;
    79→  toolUseID?: string;
    80→  parentToolUseID?: string;
    81→  isSidechain?: boolean;
    82→  userType?: string;
    83→  message?: unknown;
    84→  data?: unknown;
    85→  [key: string]: unknown;
    86→}
    87→
    88→// ─── Parsing ──────────────────────────────────────────────────────────────────
    89→
    90→/**
    91→ * Parse a full.jsonl string into an array of event objects.
    92→ * Malformed lines are silently skipped.
    93→ */
    94→export function parseFullJsonl(content: string): FullJsonlEvent[] {
    95→  const out: FullJsonlEvent[] = [];
    96→  for (const line of content.split("\n")) {
    97→    const trimmed = line.trim();
    98→    if (!trimmed) continue;
    99→    try {
   100→      out.push(JSON.parse(trimmed) as FullJsonlEvent);
   101→    } catch {
   102→      // skip malformed line
   103→    }
   104→  }
   105→  return out;
   106→}
   107→
   108→/** Return the unique key for an event, preferring uuid then messageId. */
   109→function eventKey(e: FullJsonlEvent): string | null {
   110→  return e.uuid ?? e.messageId ?? null;
   111→}
   112→
   113→// ─── Git OID mapping helper ───────────────────────────────────────────────────
   114→
   115→async function saveGitOidMapping(
   116→  db: PrismaClient,
   117→  checkpointId: string,
   118→  branch: string | null | undefined,
   119→  repoPath: string,
   120→  existingMappings?: Map<string, string>,
   121→): Promise<void> {
   122→  if (!branch) return;
   123→  try {
   124→    const commit = await findCommitForCheckpoint(repoPath, branch, checkpointId);
   125→    if (!commit) return;
   126→    const existingOid = existingMappings?.get(checkpointId);
   127→    if (existingOid === commit.hash) return; // exact (checkpointId, gitOid) pair already recorded
   128→    // OID is new or changed (e.g. after rebase) — replace old entry if present
   129→    if (existingOid) {
   130→      await db.checkpointIdGitOidJoin.delete({ where: { gitOid: existingOid } }).catch(() => {});
   131→    }
   132→    await db.checkpointIdGitOidJoin.upsert({
   133→      where: { gitOid: commit.hash },
   134→      create: { gitOid: commit.hash, checkpointId },
   135→      update: { checkpointId },
   136→    });
   137→    existingMappings?.set(checkpointId, commit.hash);
   138→  } catch {
   139→    // non-fatal — git may not be available or branch may not exist
   140→  }
   141→}
   142→
   143→// ─── Single-checkpoint indexer ────────────────────────────────────────────────
   144→
   145→/**
   146→ * Index one checkpoint directory (the folder named by the last 10 hex chars,
   147→ * e.g. `<root>/0c/b6cf391c40`).
   148→ *
   149→ * @returns Number of new messages written (already-indexed events are skipped).
   150→ */
   151→
   152→// ─── V2 helpers ───────────────────────────────────────────────────────────────
   153→
   154→async function upsertFilePath(db: PrismaClient, path: string): Promise<number> {
   155→  const existing = await db.filePath.findUnique({ where: { path }, select: { id: true } });
   156→  if (existing) return existing.id;
   157→  const created = await db.filePath.create({ data: { path } });
   158→  return created.id;
   159→}
   160→
   161→async function createTokenUsage(db: PrismaClient, tu: Record<string, unknown>): Promise<number> {
   162→  const row = await db.tokenUsage.create({
   163→    data: {
   164→      inputTokens:         Number(tu.input_tokens          ?? 0),
   165→      cacheCreationTokens: Number(tu.cache_creation_tokens ?? 0),
   166→      cacheReadTokens:     Number(tu.cache_read_tokens     ?? 0),
   167→      outputTokens:        Number(tu.output_tokens         ?? 0),
   168→      apiCallCount:        Number(tu.api_call_count        ?? 0),
   169→    },
   170→  });
   171→  return row.id;
   172→}
   173→
   174→// ─── V2 single-checkpoint indexer ────────────────────────────────────────────
   175→
   176→/**
   177→ * Index one checkpoint directory using the new normalized schema.
   178→ *
   179→ * Reads:
   180→ *   <checkpointDir>/metadata.json             → CheckpointMetadata
   181→ *   <checkpointDir>/<n>/metadata.json         → CheckpointSessionMetadata
   182→ *   <checkpointDir>/<n>/content_hash.txt      → SessionLink.contentHash (actual hash)
   183→ *   <checkpointDir>/<n>/{full.jsonl,context.md,prompt.txt} → SessionLink paths
   184→ */
   185→export async function indexCheckpointV2(
   186→  db: PrismaClient,
   187→  checkpointDir: string,
   188→  checkpointId: string,
   189→  repoPath?: string,
   190→  mappedCheckpointIds?: Set<string>,
   191→): Promise<void> {
   192→  const metaPath = join(checkpointDir, "metadata.json");
   193→  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);
   194→
   195→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   196→
   197→  // Upsert CheckpointMetadata — create TokenUsage only on first insert
   198→  let checkpointMeta = await db.checkpointMetadata.findUnique({
   199→    where: { checkpointId },
   200→    select: { id: true },
   201→  });
   202→
   203→  if (!checkpointMeta) {
   204→    let tokenUsageId: number | null = null;
   205→    if (meta.token_usage) tokenUsageId = await createTokenUsage(db, meta.token_usage);
   206→    checkpointMeta = await db.checkpointMetadata.create({
   207→      data: {
   208→        checkpointId,
   209→        cliVersion:       meta.cli_version       ?? null,
   210→        branch:           meta.branch            ?? null,
   211→        strategy:         meta.strategy          ?? null,
   212→        checkpointsCount: meta.checkpoints_count ?? 0,
   213→        tokenUsageId,
   214→      },
   215→      select: { id: true },
   216→    });
   217→  } else {
   218→    await db.checkpointMetadata.update({
   219→      where: { checkpointId },
   220→      data: {
   221→        cliVersion:       meta.cli_version       ?? null,
   222→        branch:           meta.branch            ?? null,
   223→        strategy:         meta.strategy          ?? null,
   224→        checkpointsCount: meta.checkpoints_count ?? 0,
   225→      },
   226→    });
   227→  }
   228→
   229→  // files_touched → FilePath + join table
   230→  for (const filePath of meta.files_touched ?? []) {
   231→    const filePathId = await upsertFilePath(db, filePath);
   232→    await db.checkpointMetadataFilePath.upsert({
   233→      where: { checkpointMetadataId_filePathId: { checkpointMetadataId: checkpointMeta.id, filePathId } },
   234→      create: { checkpointMetadataId: checkpointMeta.id, filePathId },
   235→      update: {},
   236→    });
   237→  }
   238→
   239→  // Session sub-directories: 0/, 1/, …
   240→  const sessionDirs = readdirSync(checkpointDir)
   241→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   242→    .sort((a, b) => parseInt(a) - parseInt(b));
   243→
   244→  for (const sessionDir of sessionDirs) {
   245→    const sessionPath    = join(checkpointDir, sessionDir);
   246→    const metadataFile   = join(sessionPath, "metadata.json");
   247→    const transcriptFile = join(sessionPath, "full.jsonl");
   248→    const contextFile    = join(sessionPath, "context.md");
   249→    const hashFile       = join(sessionPath, "content_hash.txt");
   250→    const promptFile     = join(sessionPath, "prompt.txt");
   251→
   252→    // Read actual hash content (not the file path)
   253→    const contentHash = existsSync(hashFile) ? readFileSync(hashFile, "utf8").trim() : null;
   254→
   255→    await db.sessionLink.create({
   256→      data: {
   257→        checkpointMetadataId: checkpointMeta.id,
   258→        metadata:   existsSync(metadataFile)   ? metadataFile   : null,
   259→        transcript: existsSync(transcriptFile) ? transcriptFile : null,
   260→        context:    existsSync(contextFile)    ? contextFile    : null,
   261→        contentHash,
   262→        prompt:     existsSync(promptFile)     ? promptFile     : null,
   263→      },
   264→    });
   265→
   266→    if (!existsSync(metadataFile)) continue;
   267→
   268→    const sessionMeta = JSON.parse(readFileSync(metadataFile, "utf8")) as SessionMeta;
   269→    const { session_id: sessionId } = sessionMeta;
   270→    if (!sessionId) continue;
   271→
   272→    // CheckpointSessionMetadata — create or update
   273→    let sessionRecord = await db.checkpointSessionMetadata.findUnique({
   274→      where: { checkpointId_sessionId: { checkpointId, sessionId } },
   275→      select: { id: true },
   276→    });
   277→
   278→    if (!sessionRecord) {
   279→      let sessionTokenUsageId: number | null = null;
   280→      if (sessionMeta.token_usage) {
   281→        sessionTokenUsageId = await createTokenUsage(db, sessionMeta.token_usage);
   282→      }
   283→      sessionRecord = await db.checkpointSessionMetadata.create({
   284→        data: {
   285→          checkpointId,
   286→          sessionId,
   287→          cliVersion:       sessionMeta.cli_version       ?? null,
   288→          strategy:         sessionMeta.strategy          ?? null,
   289→          createdAt:        sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   290→          branch:           sessionMeta.branch            ?? null,
   291→          checkpointsCount: sessionMeta.checkpoints_count ?? 0,
   292→          agent:            sessionMeta.agent             ?? null,
   293→          turnId:           sessionMeta.turn_id           ?? null,
   294→          tokenUsageId:     sessionTokenUsageId,
   295→        },
   296→        select: { id: true },
   297→      });
   298→    } else {
   299→      await db.checkpointSessionMetadata.update({
   300→        where: { checkpointId_sessionId: { checkpointId, sessionId } },
   301→        data: {
   302→          cliVersion: sessionMeta.cli_version ?? null,
   303→          strategy:   sessionMeta.strategy    ?? null,
   304→          createdAt:  sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   305→          branch:     sessionMeta.branch      ?? null,
   306→          agent:      sessionMeta.agent       ?? null,
   307→          turnId:     sessionMeta.turn_id     ?? null,
   308→        },
   309→      });
   310→    }
   311→
   312→    // files_touched for session
   313→    for (const filePath of sessionMeta.files_touched ?? []) {
   314→      const filePathId = await upsertFilePath(db, filePath);
   315→      await db.checkpointSessionMetadataFilePath.upsert({
   316→        where: {
   317→          checkpointSessionMetadataId_filePathId: {
   318→            checkpointSessionMetadataId: sessionRecord.id,
   319→            filePathId,
   320→          },
   321→        },
   322→        create: { checkpointSessionMetadataId: sessionRecord.id, filePathId },
   323→        update: {},
   324→      });
   325→    }
   326→
   327→    // initial_attribution
   328→    if (sessionMeta.initial_attribution) {
   329→      const ia = sessionMeta.initial_attribution as Record<string, unknown>;
   330→      const iaData = {
   331→        calculatedAt:    ia.calculated_at ? new Date(ia.calculated_at as string) : null,
   332→        agentLines:      Number(ia.agent_lines      ?? 0),
   333→        humanAdded:      Number(ia.human_added      ?? 0),
   334→        humanModified:   Number(ia.human_modified   ?? 0),
   335→        humanRemoved:    Number(ia.human_removed    ?? 0),
   336→        totalCommitted:  Number(ia.total_committed  ?? 0),
   337→        agentPercentage: Number(ia.agent_percentage ?? 0),
   338→      };
   339→      await db.initialAttribution.upsert({
   340→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   341→        create: { checkpointSessionMetadataId: sessionRecord.id, ...iaData },
   342→        update: iaData,
   343→      });
   344→    }
   345→
   346→    // summary
   347→    if (sessionMeta.summary) {
   348→      const sm = sessionMeta.summary;
   349→      const summaryRecord = await db.checkpointSessionSummary.upsert({
   350→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   351→        create: { checkpointSessionMetadataId: sessionRecord.id, intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   352→        update: { intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   353→        select: { id: true },
   354→      });
   355→
   356→      // Recreate child arrays on every index pass (preserve status/subSessionId on OpenItem)
   357→      await Promise.all([
   358→        db.frictionItem.deleteMany( { where: { checkpointSessionSummaryId: summaryRecord.id } }),
   359→        db.repoLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   360→        db.codeLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   361→        db.workflowItem.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   362→      ]);
   363→
   364→      const creates: Promise<unknown>[] = [];
   365→
   366→      if (sm.open_items?.length) {
   367→        // Look up prior statuses for this session so they survive new checkpoints being indexed.
   368→        // Fetch ALL non-open prior items (not just exact matches) so we can fuzzy-match rephrased items.
   369→        const priorItems = await db.openItem.findMany({
   370→          where: {
   371→            checkpointSessionSummary: {
   372→              checkpointSessionMetadata: { sessionId },
   373→            },
   374→            status: { notIn: ["open"] },
   375→          },
   376→          select: { text: true, status: true, subSessionId: true },
   377→          distinct: ["text"],
   378→          orderBy: { id: "desc" },
   379→        });
   380→
   381→        // Build a map for exact matches and a list for fuzzy fallback
   382→        const priorByText = new Map(priorItems.map((p) => [p.text, p]));
   383→
   384→        // Jaccard similarity on word tokens (case-insensitive, punctuation-stripped)
   385→        function tokenize(s: string): Set<string> {
   386→          return new Set(s.toLowerCase().replace(/[^\w\s]/g, " ").split(/\s+/).filter(Boolean));
   387→        }
   388→        function jaccardSimilarity(a: string, b: string): number {
   389→          const ta = tokenize(a);
   390→          const tb = tokenize(b);
   391→          let intersection = 0;
   392→          for (const w of ta) if (tb.has(w)) intersection++;
   393→          const union = ta.size + tb.size - intersection;
   394→          return union === 0 ? 0 : intersection / union;
   395→        }
   396→
   397→        function findBestPrior(text: string) {
   398→          // Exact match first
   399→          if (priorByText.has(text)) return priorByText.get(text);
   400→          // Fuzzy fallback: best Jaccard match above 0.5 threshold
   401→          let best: { text: string; status: string; subSessionId: string | null } | undefined;
   402→          let bestScore = 0.5; // minimum threshold
   403→          for (const prior of priorItems) {
   404→            const score = jaccardSimilarity(text, prior.text);
   405→            if (score > bestScore) { bestScore = score; best = prior; }
   406→          }
   407→          return best;
   408→        }
   409→
   410→        creates.push(...sm.open_items.map((text) => {
   411→          const prior = findBestPrior(text);
   412→          return db.openItem.upsert({
   413→            where: { checkpointSessionSummaryId_text: { checkpointSessionSummaryId: summaryRecord.id, text } },
   414→            create: {
   415→              checkpointSessionSummaryId: summaryRecord.id,
   416→              text,
   417→              status: prior?.status ?? "open",
   418→              subSessionId: prior?.subSessionId ?? null,
   419→            },
   420→            update: {},
   421→          });
   422→        }));
   423→        // Remove open items that no longer appear in the source
   424→        creates.push(
   425→          db.openItem.deleteMany({
   426→            where: { checkpointSessionSummaryId: summaryRecord.id, text: { notIn: sm.open_items } },
   427→          })
   428→        );
   429→      } else {
   430→        creates.push(db.openItem.deleteMany({ where: { checkpointSessionSummaryId: summaryRecord.id } }));
   431→      }
   432→      if (sm.friction?.length) {
   433→        creates.push(db.frictionItem.createMany({
   434→          data: sm.friction.map((text) => ({ checkpointSessionSummaryId: summaryRecord.id, text })),
   435→        }));
   436→      }
   437→      if (sm.learnings?.repo?.length) {
   438→        creates.push(db.repoLearning.createMany({
   439→          data: sm.learnings.repo.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   440→        }));
   441→      }
   442→      if (sm.learnings?.code?.length) {
   443→        creates.push(db.codeLearning.createMany({
   444→          data: sm.learnings.code.map(({ path, finding }) => ({
   445→            checkpointSessionMetadataId: summaryRecord.id,
   446→            path,
   447→            finding,
   448→          })),
   449→        }));
   450→      }
   451→      if (sm.learnings?.workflow?.length) {
   452→        creates.push(db.workflowItem.createMany({
   453→          data: sm.learnings.workflow.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   454→        }));
   455→      }
   456→
   457→      await Promise.all(creates);
   458→    }
   459→  }
   460→
   461→  if (repoPath && !mappedCheckpointIds?.has(checkpointId)) {
   462→    await saveGitOidMapping(db, checkpointId, meta.branch, repoPath);
   463→  }
   464→}
   465→
   466→// ─── V2 full-tree indexer ─────────────────────────────────────────────────────
   467→
   468→export async function indexAllCheckpointsV2(
   469→  db: PrismaClient,
   470→  rootDir: string,
   471→  onProgress?: (checkpointId: string) => void,
   472→  repoPath?: string,
   473→): Promise<{ checkpoints: number }> {
   474→  let totalCheckpoints = 0;
   475→
